/**
 * Goal Persistence System
 * Nexus Strategic Planning - Long-term Goal Management
 * 
 * Goals are higher-level than tasks. They persist across sessions
 * and provide strategic direction for task creation.
 */

import { readFile, writeFile, mkdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';

/**
 * Goal status
 */
export type GoalStatus = 'active' | 'completed' | 'deferred' | 'abandoned';

/**
 * Goal priority
 */
export type GoalPriority = 'critical' | 'high' | 'medium' | 'low';

/**
 * Completion criterion
 */
export interface CompletionCriterion {
  description: string;
  completed: boolean;
  completedAt?: string;
}

/**
 * Goal object
 */
export interface Goal {
  id: string;
  title: string;
  description: string;
  status: GoalStatus;
  priority: GoalPriority;
  createdAt: string;
  completedAt?: string;
  deferralReason?: string;
  completionCriteria: CompletionCriterion[];
  // Link to LTM insights
  ltmInsightId?: string;
  // Related sessions
  relatedSessions: string[];
  // Tags for categorization
  tags: string[];
  // Progress tracking
  progress: number; // 0-100
}

/**
 * Goals manifest
 */
export interface GoalsManifest {
  version: string;
  lastUpdated: string;
  activeGoals: string[];
  completedGoals: string[];
  deferredGoals: string[];
  abandonedGoals: string[];
}

/**
 * Goal storage configuration
 */
const GOALS_DATA_DIR = './data';
const GOALS_FILE = path.join(GOALS_DATA_DIR, 'goals.json');
const GOALS_MANIFEST_FILE = path.join(GOALS_DATA_DIR, 'goals_manifest.json');

/**
 * Goal Manager
 * Handles persistence and retrieval of goals
 */
export class GoalManager {
  private goals: Map<string, Goal> = new Map();
  private manifest: GoalsManifest;
  private initialized = false;

  constructor() {
    this.manifest = {
      version: '1.0.0',
      lastUpdated: new Date().toISOString(),
      activeGoals: [],
      completedGoals: [],
      deferredGoals: [],
      abandonedGoals: []
    };
  }

  /**
   * Initialize the goal manager
   */
  async initialize(): Promise<void> {
    if (this.initialized) return;

    // Ensure directory exists
    if (!existsSync(GOALS_DATA_DIR)) {
      await mkdir(GOALS_DATA_DIR, { recursive: true });
    }

    // Load existing goals
    await this.loadGoals();

    this.initialized = true;
  }

  /**
   * Load goals from disk
   */
  private async loadGoals(): Promise<void> {
    try {
      // Load manifest
      if (existsSync(GOALS_MANIFEST_FILE)) {
        const manifestData = await readFile(GOALS_MANIFEST_FILE, 'utf-8');
        this.manifest = JSON.parse(manifestData);
      }

      // Load goals
      if (existsSync(GOALS_FILE)) {
        const goalsData = await readFile(GOALS_FILE, 'utf-8');
        const goals: Goal[] = JSON.parse(goalsData);
        this.goals.clear();
        for (const goal of goals) {
          this.goals.set(goal.id, goal);
        }
      }
    } catch (error) {
      console.error('[GoalManager] Error loading goals:', error);
      // Start fresh on error
      this.goals.clear();
    }
  }

  /**
   * Save goals to disk
   */
  private async saveGoals(): Promise<void> {
    try {
      // Update manifest
      this.manifest.lastUpdated = new Date().toISOString();
      await writeFile(GOALS_MANIFEST_FILE, JSON.stringify(this.manifest, null, 2));

      // Save all goals
      const goals = Array.from(this.goals.values());
      await writeFile(GOALS_FILE, JSON.stringify(goals, null, 2));
    } catch (error) {

/**
 * Task Tracker - Session-Level Action Management
 * 
 * For concrete, actionable tasks during a session.
 * Tasks can:
 * - Link to goals (but exist independently)
 * - Have subtasks (responsibilities)
 * - Track time estimates and actual duration
 * - Signal completion to parent tasks
 * - Carry tags/categories for filtering
 * 
 * Key differences from Goals:
 * - Goals: Multi-session, strategic
 * - Tasks: Session-specific, tactical
 */
import * as fs from 'fs';
import * as path from 'path';

export interface Task {
  id: string;
  title: string;
  description: string;
  status: 'pending' | 'active' | 'completed' | 'canceled' | 'deferred';
  priority: 'critical' | 'high' | 'medium' | 'low';
  createdAt: string;
  startedAt?: string;
  completedAt?: string;
  estimatedMinutes?: number;
  actualMinutes?: number;
  goalId?: string;
  parentTaskId?: string;
  tags: string[];
  subtaskIds: string[];
  notes: string[];
  autoCompleteOnSubtasks: boolean; // If true, completes when all subtasks done
}

const TASKS_DIR = 'history';
const TASKS_FILE = path.join(TASKS_DIR, 'tasks_manifest.json');
let taskIdCounter = 0;

export interface TaskOptions {
  priority?: Task['priority'];
  estimatedMinutes?: number;
  goalId?: string;
  parentTaskId?: string;
  tags?: string[];
  autoCompleteOnSubtasks?: boolean;
}

export class TaskTracker {
  private tasks: Map<string, Task> = new Map();
  private activeTaskId: string | null = null;

  constructor() {
    this.ensureDir();
    this.loadTasks();
  }

  private ensureDir(): void {
    if (!fs.existsSync(TASKS_DIR)) {
      fs.mkdirSync(TASKS_DIR, { recursive: true });
    }
  }

  /**
   * Create a new task
   * @param title - Brief action title
   * @param description - Detailed description
   * @param options - Optional task configuration
   * @returns The created Task
   */
  createTask(
    title: string,
    description: string,
    options: TaskOptions = {}
  ): Task {
    taskIdCounter++;

    const task: Task = {
      id: `task_${Date.now()}_${taskIdCounter}`,
      title,
      description,
      status: 'pending',
      priority: options.priority ?? 'medium',
      createdAt: new Date().toISOString(),
      tags: options.tags ?? [],
      subtaskIds: [],
      notes: [],
      autoCompleteOnSubtasks: options.autoCompleteOnSubtasks ?? false,
    };

    // Only add optional fields if they have values (not undefined)
    if (options.estimatedMinutes !== undefined) {
      task.estimatedMinutes = options.estimatedMinutes;
    }
    if (options.goalId !== undefined) {
      task.goalId = options.goalId;
    }
    if (options.parentTaskId !== undefined) {
      task.parentTaskId = options.parentTaskId;
    }

    this.tasks.set(task.id, task);

    // If this is a subtask, link to parent
    if (options.parentTaskId) {
      const parent = this.tasks.get(options.parentTaskId);
      if (parent && !parent.subtaskIds.includes(task.id)) {
        parent.subtaskIds.push(task.id);
        this.saveTasks();
      }
    }

    this.saveTasks();
    return task;
  }

  /**
   * Start working on a task
   */
  startTask(taskId: string): Task | null {
    const task = this.tasks.get(taskId);
    if (!task) return null;

    // End current active task timing
    if (this.activeTaskId && this.activeTaskId !== taskId) {
      this.pauseTask(this.activeTaskId);
    }

    task.status = 'active';
    task.startedAt = task.startedAt ?? new Date().toISOString();
    this.activeTaskId = taskId;

    this.saveTasks();
    return task;
  }

  /**
   * Pause an active task (stops timing)
   */
  pauseTask(taskId: string): Task | null {
    const task = this.tasks.get(taskId);
    if (!task) return null;

    if (this.activeTaskId === taskId) {
      this.activeTaskId = null;
    }

    // Calculate actual minutes spent
    if (task.startedAt) {
      const startTime = new Date(task.startedAt).getTime();
      const elapsedMinutes = (Date.now() - startTime) / 60000;
      task.actualMinutes = (task.actualMinutes ?? 0) + elapsedMinutes;
    }

    if (task.status === 'active') {
      task.status = 'pending';
    }

    this.saveTasks();
    return task;
  }

  /**
   * Complete a task
   * Triggers auto-completion check for parent tasks
   */
  completeTask(taskId: string, notes?: string): Task | null {
    const task = this.tasks.get(taskId);
    if (!task) return null;

    const wasActive = this.activeTaskId === taskId;

    task.status = 'completed';
    task.completedAt = new Date().toISOString();

    // Add completion note if provided
    if (notes) {
      task.notes.push(`Completed: ${notes}`);
    }

    // Clear active status
    if (wasActive) {
      this.activeTaskId = null;
    }

    this.saveTasks();

    // Check parent task auto-completion
    if (task.parentTaskId) {
      this.checkParentAutoComplete(task.parentTaskId);
    }

    return task;
  }

  /**
   * Mark task as canceled
   */

    completed: number;
    canceled: number;
    deferred: number;
    completionRate: number;
  } {
    const all = this.getAllTasks();
    const completed = all.filter(t => t.status === 'completed').length;
    const canceled = all.filter(t => t.status === 'canceled').length;
    const totalDone = completed + canceled;

    return {
      total: all.length,
      pending: all.filter(t => t.status === 'pending').length,
      active: all.filter(t => t.status === 'active').length,
      completed,
      canceled,
      deferred: all.filter(t => t.status === 'deferred').length,
      completionRate: totalDone > 0 ? Math.round((completed / totalDone) * 100) : 0,
    };
  }

  /**
   * Archive completed/canceled tasks older than specified days
   */
  archiveOldTasks(days: number = 7): Task[] {
    const cutoff = new Date();
    cutoff.setDate(cutoff.getDate() - days);

    const archived: Task[] = [];
    for (const [id, task] of this.tasks) {
      if ((task.status === 'completed' || task.status === 'canceled') &&
          task.completedAt && new Date(task.completedAt) < cutoff) {
        archived.push(task);
        this.tasks.delete(id);
      }
    }

    if (archived.length > 0) {
      this.saveTasks();
      // Also archive to separate file
      const archiveFile = path.join(TASKS_DIR, 'tasks_archive.json');
      const existing: Task[] = fs.existsSync(archiveFile) 
        ? JSON.parse(fs.readFileSync(archiveFile, 'utf-8')).tasks 
        : [];
      fs.writeFileSync(archiveFile, JSON.stringify(
        { tasks: [...existing, ...archived] }, null, 2), 'utf-8');
    }

    return archived;
  }

  /**
   * Delete a task permanently (use with caution)
   */
  deleteTask(taskId: string): boolean {
    const task = this.tasks.get(taskId);
    if (!task) return false;

    // Remove from parent's subtask list
    if (task.parentTaskId) {
      const parent = this.tasks.get(task.parentTaskId);
      if (parent) {
        parent.subtaskIds = parent.subtaskIds.filter(id => id !== taskId);
      }
    }

    // Re-parent subtasks
    for (const subtaskId of task.subtaskIds) {
      const subtask = this.tasks.get(subtaskId);
      if (subtask) {
        if (task.parentTaskId === undefined) { delete (subtask as any).parentTaskId; } else { subtask.parentTaskId = task.parentTaskId; }
        if (task.parentTaskId) {
          const parent = this.tasks.get(task.parentTaskId);
          if (parent && !parent.subtaskIds.includes(subtaskId)) {
            parent.subtaskIds.push(subtaskId);
          }
        }
      }
    }

    if (this.activeTaskId === taskId) {
      this.activeTaskId = null;
    }

    this.tasks.delete(taskId);
    this.saveTasks();
    return true;
  }

  private checkParentAutoComplete(parentId: string): void {
    const parent = this.tasks.get(parentId);
    if (!parent || !parent.autoCompleteOnSubtasks) return;

    const subtasks = this.getSubtasks(parentId);
    const allCompleted = subtasks.length > 0 && subtasks.every(st => st.status === 'completed');

    if (allCompleted && parent.status !== 'completed') {
      parent.status = 'completed';
      parent.completedAt = new Date().toISOString();
      parent.notes.push('Auto-completed: All subtasks finished.');
      this.saveTasks();

      // Recursively check chain
      if (parent.parentTaskId) {
        this.checkParentAutoComplete(parent.parentTaskId);
      }
    }
  }

  private loadTasks(): void {
    if (!fs.existsSync(TASKS_FILE)) return;

    // Defensive: check file size and content
    const stats = fs.statSync(TASKS_FILE);
    if (stats.size === 0) return;

    const content = fs.readFileSync(TASKS_FILE, 'utf-8');
    if (!content.trim()) return;

    try {
      const manifest = JSON.parse(content);
      for (const data of manifest.tasks) {
        this.tasks.set(data.id, data);
        // Maintain counter
        const match = data.id.match(/task_(\d+)_(\d+)$/);
        if (match) {
          const counter = parseInt(match[2], 10);
          if (counter > taskIdCounter) {
            taskIdCounter = counter;
          }
        }
      }
    } catch (err) {
      console.error('Failed to parse tasks manifest, starting fresh:', err);
      // Continue with empty tasks
    }
  }

  private saveTasks(): void {
    const data = {
      tasks: Array.from(this.tasks.values()),
      activeTaskId: this.activeTaskId,
    };
    fs.writeFileSync(TASKS_FILE, JSON.stringify(data, null, 2), 'utf-8');
  }
}

// Export singleton for module-level access
export const taskTracker = new TaskTracker();
export const tasks = taskTracker;

import type { ToolPlugin } from "../manager";
import { tasks, type Task } from "../../task_tracker";

interface TaskInfo {
  id: string;
  title: string;
  description: string;
  status: Task['status'];
  priority: Task['priority'];
  progress: number;
  subtaskCount: number;
  tags: string[];
  estimatedMinutes?: number;
  actualMinutes?: number;
  createdAt: string;
  completedAt?: string;
  notes: string[];
}

interface TaskListResult {
  success: boolean;
  activeTask?: TaskInfo | null;
  tasks: TaskInfo[];
  stats: {
    total: number;
    pending: number;
    active: number;
    completed: number;
    completionRate: number;
  };
}

interface TaskActionResult {
  success: boolean;
  taskId?: string;
  message: string;
  task?: TaskInfo;
}

function toTaskInfo(task: Task): TaskInfo {
  return {
    id: task.id,
    title: task.title,
    description: task.description,
    status: task.status,
    priority: task.priority,
    progress: tasks.getCompletionPercentage(task.id),
    subtaskCount: task.subtaskIds.length,
    tags: task.tags,
    ...(task.estimatedMinutes !== undefined && { estimatedMinutes: task.estimatedMinutes }),
    ...(task.actualMinutes !== undefined && { actualMinutes: task.actualMinutes }),
    createdAt: task.createdAt,
    ...(task.completedAt !== undefined && { completedAt: task.completedAt }),
    notes: task.notes,
  };
}

export const taskPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "task_manager",
      description: "Manage and track work tasks. Create, start, complete, list, and organize tasks with priorities, subtasks, and time tracking.",
      parameters: {
        type: "object",
        properties: {
          action: {
            type: "string",
            enum: ["list", "create", "start", "complete", "cancel", "defer", "add_subtask", "add_note", "add_tag", "get_stats", "get_by_tag", "delete"],
            description: "The action to perform",
          },
          task_id: {
            type: "string",
            description: "Task ID for the target task (required for start, complete, cancel, defer, add_note, add_tag, delete, and add_subtask)",
          },
          title: {
            type: "string",
            description: "Task title (required for create and add_subtask)",
          },
          description: {
            type: "string",
            description: "Detailed task description",
          },
          priority: {
            type: "string",
            enum: ["critical", "high", "medium", "low"],
            description: "Task priority. Default: medium",
          },
          estimated_minutes: {
            type: "number",
            description: "Estimated time in minutes",
          },
          goal_id: {
            type: "string",
            description: "Optional goal ID to link this task to",
          },
          parent_task_id: {
            type: "string",
            description: "Parent task ID (creates a subtask relationship)",
          },
          auto_complete: {
            type: "boolean",
            description: "If true, parent task auto-completes when all subtasks done",
          },
          tags: {
            type: "array",
            items: { type: "string" },
            description: "Tags to apply to the task",
          },
          note: {
            type: "string",
            description: "Note content (for add_note) or reason (for cancel/defer)",
          },
          tag: {
            type: "string",
            description: "Tag to add (for add_tag) or search by (for get_by_tag)",
          },
          status_filter: {
            type: "string",
            enum: ["pending", "active", "completed", "canceled", "deferred", "all"],
            description: "Filter tasks by status (for list action)",
          },
        },
        required: ["action"],
      },
    },
  },
  execute: (args: {
    action: string;
    task_id?: string;
    title?: string;
    description?: string;
    priority?: Task['priority'];
    estimated_minutes?: number;
    goal_id?: string;
    parent_task_id?: string;
    auto_complete?: boolean;
    tags?: string[];
    note?: string;
    tag?: string;
    status_filter?: string;
  }): string => {
    try {
      switch (args.action) {
        case "list": {
          const activeTask = tasks.getActiveTask();
          let taskList: Task[];

          if (args.status_filter && args.status_filter !== 'all') {
            taskList = tasks.getTasksByStatus(args.status_filter as Task['status']);
          } else {
            taskList = tasks.getAllTasks();
          }

          const result: TaskListResult = {
            success: true,
            activeTask: activeTask ? toTaskInfo(activeTask) : null,
            tasks: taskList.map(toTaskInfo),
            stats: tasks.getStats(),
          };

          return JSON.stringify(result);
        }

        case "create": {
          if (!args.title) {
            return JSON.stringify({
              success: false,
              message: "Title is required for create action",
            });
          }

          const opts: {
            priority?: Task['priority'];
            estimatedMinutes?: number;
            goalId?: string;
            parentTaskId?: string;
            tags?: string[];
            autoCompleteOnSubtasks?: boolean;
          } = {};

          if (args.priority !== undefined) opts.priority = args.priority;
          if (args.estimated_minutes !== undefined) opts.estimatedMinutes = args.estimated_minutes;
          if (args.goal_id !== undefined) opts.goalId = args.goal_id;
          if (args.parent_task_id !== undefined) opts.parentTaskId = args.parent_task_id;
          if (args.tags !== undefined) opts.tags = args.tags;
          if (args.auto_complete !== undefined) opts.autoCompleteOnSubtasks = args.auto_complete;

          const task = tasks.createTask(args.title, args.description ?? "", opts);

          return JSON.stringify({
            success: true,
            taskId: task.id,
            message: `Created task: ${task.title}`,
            task: toTaskInfo(task),
          });
        }

        case "start": {
